CREATE DEFINER=`root`@`localhost` PROCEDURE `allDoctores` ()  BEGIN
SELECT es.codigoEstablecimiento,es.nombreEstablecimiento,es.longitudEstablecimiento,
es.latitudEstablecimiento,d.codigoDoctor,d.nombreDoctor,d.apellidoDoctor,d.rneDoctor,
e.nombreEspecialidad,d.numColegiaturaDoctor,d.descripcionTipoAtencionDoctor,
d.precioAtencionDoctor,d.facebookDoctor,d.instagramDoctor,d.telefonoDoctor
FROM doctor AS d JOIN establecimientodesalud as es ON es.codigoEstablecimiento=d.codigoEstablecimiento
JOIN especialidades as e ON e.codigoEspecialidad=d.codigoEspecialidad
WHERE d.estadoDoctor='a' and d.mostrarDoctor='s'and es.estadoEstablecimiento='a' AND es.mostrarEstablecimiento='s';
END$$

