CREATE DEFINER=`root`@`localhost` PROCEDURE `deletEstablecimientoSalud` (`codEstablecimiento` INT)  BEGIN
DELETE es,ese,doc FROM establecimientodesalud AS es 
LEFT JOIN establecimientodesaludespecialidades AS ese 
ON es.codigoEstablecimiento=ese.codigoEstablecimiento 
LEFT JOIN doctor as doc ON es.codigoEstablecimiento=doc.codigoEstablecimiento 
where es.codigoEstablecimiento=codEstablecimiento;
END$$

