CREATE DEFINER=`root`@`localhost` PROCEDURE `selectEspecialidadesRegistradasEnEstablecimientos` ()  BEGIN
SELECT DISTINCT e.nombreEspecialidad, e.codigoEspecialidad from especialidades as e 
JOIN doctor as d ON e.codigoEspecialidad=d.codigoEspecialidad 
JOIN establecimientodesalud as est ON est.codigoEstablecimiento=d.codigoEstablecimiento 
WHERE d.estadoDoctor='a' AND d.mostrarDoctor='s' AND e.estadoEspecialidad='a' 
AND est.estadoEstablecimiento='a' AND est.mostrarEstablecimiento='s' ORDER BY e.nombreEspecialidad ASC;
END$$

