CREATE DEFINER=`root`@`localhost` PROCEDURE `updateRepresentante` (IN `codigorepresentante` INT, IN `nombre` VARCHAR(30), IN `apellido` VARCHAR(30), IN `dni` VARCHAR(8), IN `correo` VARCHAR(50), IN `pass` VARCHAR(50), IN `estado` CHAR(1), IN `tipo` CHAR(1), IN `mostrarEstable` CHAR(1))  BEGIN
UPDATE representante as r 
JOIN establecimientodesalud as e ON e.codigoRe=r.codigoRe 
SET r.nombreRe=nombre, 
r.apellidoRe=apellido, 
r.dniRe=dni, 
r.correoRe=correo,
r.passwordRe=pass, 
r.estadoRe=estado,
r.tipoRe=tipo,
e.mostrarEstablecimiento=mostrarEstable
WHERE r.codigoRe=codigorepresentante;
END$$

